INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('amamentacao', 'Meu bebê mama muito rápido, está comendo pouco?', 'Nem sempre! Alguns bebês são rápidos mesmo. Se está ganhando peso e fazendo cocô, está tudo bem.', 'amamentacao', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('amamentacao', 'Posso amamentar deitada?', 'Sim! É até mais confortável. Só toma cuidado para não adormecer com o bebê na cama.', 'amamentacao', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('amamentacao', 'Meu leite vaza muito, é normal?', 'Sim! Especialmente nos primeiros meses. Usa absorvente de seio para não molhar a roupa. Produto: **Absorventes de seio descartáveis** (salva a roupa!).', 'amamentacao', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('amamentacao', 'Posso amamentar com piercing no seio?', 'Depende! Se o piercing está bem cicatrizado, pode tirar na hora de amamentar. Converse com seu pediatra.', 'amamentacao', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('amamentacao', 'Bebê pode morder o peito enquanto amamenta?', 'Sim, pode! Especialmente quando começa a nascer dente. Se dói, tira o bebê do peito e oferece de novo.', 'amamentacao', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('amamentacao', 'Meu bebê não quer soltar o peito, é normal?', 'Sim! Alguns bebês adoram ficar no peito. Se ele está comendo bem, deixa ele ficar um pouco.', 'amamentacao', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('amamentacao', 'Posso amamentar durante a menstruação?', 'Sim! A menstruação não afeta o leite. Amamenta normalmente.', 'amamentacao', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('amamentacao', 'Meu leite tem gosto estranho, o bebê não quer?', 'Alguns alimentos mudam o gosto do leite. Tenta evitar alimentos muito fortes (alho, cebola). Mas leite materno é sempre bom!', 'amamentacao', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('amamentacao', 'Posso amamentar se estou tomando remédio?', 'Depende do remédio! Alguns são seguros, outros não. Sempre converse com o pediatra antes de tomar qualquer coisa.', 'amamentacao', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('amamentacao', 'Meu bebê mama e depois chora de fome, o leite não sustenta?', 'Pode ser que ele não está pegando bem. Ou pode ser que precisa mamar mais vezes. Tenta aumentar a frequência!', 'amamentacao', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('alimentacao', 'Com quantos meses posso começar a dar comida sólida?', 'Geralmente com 6 meses! Mas alguns bebês mostram sinais antes (sentar sozinho, interessar por comida). Converse com o pediatra.', 'alimentacao', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('alimentacao', 'Como saber se meu bebê está pronto para comer?', 'Senta sozinho, consegue segurar a cabeça firme, e mostra interesse por comida. Se tem esses sinais, pode começar!', 'alimentacao', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('alimentacao', 'Qual é a primeira comida que devo dar?', 'Geralmente frutas ou vegetais amassados. Maçã, banana, abóbora são boas opções. Começa com uma colherada!', 'alimentacao', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('alimentacao', 'Meu bebê cospe a comida, devo insistir?', 'Não! Cospe é reflexo. Tenta novamente em alguns dias. Cada bebê tem seu tempo.', 'alimentacao', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('alimentacao', 'Posso dar mel para bebê?', 'Não! Antes de 1 ano, nada de mel. Risco de botulismo. Depois de 1 ano, tudo bem.', 'alimentacao', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('alimentacao', 'Meu bebê engasgou com comida, o que faço?', 'Deixa ele tossir! A tosse é o mecanismo natural para desengasgar. Se ele não conseguir respirar, procura emergência.', 'alimentacao', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('alimentacao', 'Bebê pode comer ovo inteiro?', 'Sim! Ovo é super nutritivo. Começa com a gema cozida, depois oferece a clara também.', 'alimentacao', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('alimentacao', 'Quantas vezes por dia bebê deve comer?', 'Começa com 1 vez ao dia, depois aumenta para 2-3. Mas continua amamentando! Leite é o principal.', 'alimentacao', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('alimentacao', 'Posso dar sal na comida do bebê?', 'Não! Sal prejudica os rins do bebê. Usa ervas (cebolinha, salsinha) para dar sabor.', 'alimentacao', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('alimentacao', 'Meu bebê não quer comer, é normal?', 'Sim! Alguns bebês têm menos interesse no começo. Tenta oferecer de novo em alguns dias. Sem forçar!', 'alimentacao', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('alimentacao', 'Posso dar suco para bebê?', 'Melhor dar a fruta inteira! Suco perde fibra. Se der suco, é só um pouco e bem diluído em água.', 'alimentacao', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('alimentacao', 'Bebê pode comer chocolate?', 'Melhor não! Chocolate tem cafeína e açúcar. Depois de 1 ano, um pouco tudo bem, mas sem exagero.', 'alimentacao', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('alimentacao', 'Meu bebê só quer leite e rejeita comida, devo me preocupar?', 'Não! Alguns bebês demoram mais. Continua oferecendo comida sem forçar. Um dia ele come!', 'alimentacao', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('alimentacao', 'Posso dar iogurte para bebê?', 'Sim! Iogurte natural é ótimo. Sem açúcar! Produto útil: **Iogurte natural integral** (melhor que os açucarados).', 'alimentacao', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('alimentacao', 'Bebê pode comer peixe?', 'Sim! Peixe é ótimo para o desenvolvimento. Começa com peixes brancos (linguado, tilápia) que são mais suaves.', 'alimentacao', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('febre', 'Qual temperatura é considerada febre?', 'Acima de 37.8°C é febre. Mas não é emergência! Observa o bebê. Se está feliz e comendo, pode ser só uma infecção passageira.', 'febre', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('febre', 'Meu bebê tem febre, devo ir para o hospital?', 'Depende! Se tem menos de 3 meses e febre acima de 38°C, vai ao hospital. Se tem mais de 3 meses, observa por 24h. Se piorar, vai!', 'febre', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('febre', 'Como baixar a febre do bebê?', 'Roupa leve, banho morno (não frio!), e muito líquido. Medicação só com receita do pediatra!', 'febre', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('febre', 'Posso dar banho em bebê com febre?', 'Sim! Banho morno ajuda a baixar a febre. Evita água muito fria.', 'febre', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('febre', 'Febre é bom ou ruim?', 'Febre é a defesa do corpo! É bom, significa que o corpo está lutando contra a infecção. Não é inimiga!', 'febre', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('febre', 'Meu bebê tem febre e vomita, é grave?', 'Pode ser! Se vomita muito ou não consegue beber líquido, procura o pediatra.', 'febre', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('febre', 'Bebê com febre pode dormir?', 'Sim! Dormir ajuda o corpo a se recuperar. Deixa dormir!', 'febre', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('febre', 'Meu bebê tem febre há 3 dias, devo me preocupar?', 'Sim! Procura o pediatra. Febre muito prolongada precisa de investigação.', 'febre', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('febre', 'Febre causa convulsão?', 'Pode! Febre muito alta (acima de 39°C) em bebês pequenos pode causar convulsão febril. Procura emergência se isso acontecer.', 'febre', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('febre', 'Posso usar remédio para febre sem receita?', 'Não! Sempre com receita do pediatra. Nunca automédica!', 'febre', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('febre', 'Meu bebê tem febre e está muito molinho, é perigoso?', 'Sim! Bebê molinho com febre é sinal de algo grave. Vai para emergência AGORA!', 'febre', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('febre', 'Febre depois da vacina é normal?', 'Sim! Febre leve depois da vacina é resposta do corpo. Geralmente passa em 24-48h.', 'febre', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('febre', 'Como medir a febre corretamente?', 'Termômetro digital é o melhor. Coloca embaixo do braço ou na testa. Não usa termômetro de mercúrio!', 'febre', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('febre', 'Bebê com febre pode sair de casa?', 'Melhor não! Febre significa que há algo acontecendo. Fica em casa descansando.', 'febre', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('febre', 'Meu bebê tem febre mas está comendo bem, é sinal de que não é grave?', 'Pode ser! Mas não ignore. Observa por 24h. Se continuar, procura o pediatra.', 'febre', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('desenvolvimento', 'Quando bebê começa a sorrir?', 'Entre 4-8 semanas! Pode ser sorriso reflexo no começo, mas depois é de verdade! Que emoção! 💙', 'desenvolvimento', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('desenvolvimento', 'Meu bebê não segura a cabeça ainda, devo me preocupar?', 'Não! Cada bebê tem seu tempo. Geralmente entre 1-3 meses consegue. Tenta fazer tummy time!', 'desenvolvimento', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('desenvolvimento', 'Como fazer tummy time?', 'Coloca o bebê de bruços no chão ou na sua barriguinha por alguns minutos. Começa com pouco tempo e aumenta gradualmente.', 'desenvolvimento', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('desenvolvimento', 'Meu bebê não rola ainda, é normal?', 'Sim! Rolar geralmente acontece entre 4-6 meses. Não força! Deixa o bebê explorar.', 'desenvolvimento', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('desenvolvimento', 'Meu bebê não pega brinquedo, é atraso?', 'Não! Pegar brinquedo começa com 4-5 meses. Se seu bebê tem menos que isso, é normal.', 'desenvolvimento', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('desenvolvimento', 'Como estimular o desenvolvimento do bebê?', 'Conversa com ele! Canta, mostra cores, texturas diferentes. Brincadeira é a melhor estimulação!', 'desenvolvimento', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('desenvolvimento', 'Meu bebê não responde ao nome, devo me preocupar?', 'Não ainda! Responder ao nome geralmente começa com 6-9 meses. Mas continua chamando!', 'desenvolvimento', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('desenvolvimento', 'Quando bebê começa a falar?', 'Primeiros sons entre 2-4 meses, primeiras palavras entre 12-18 meses. Cada bebê é diferente!', 'desenvolvimento', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('desenvolvimento', 'Meu bebê não faz contato visual, é sinal de autismo?', 'Não necessariamente! Bebês pequenos ainda estão aprendendo. Mas se você está preocupada, converse com o pediatra.', 'desenvolvimento', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('desenvolvimento', 'Bebê pode ficar de bruços para dormir?', 'Não! Para dormir, sempre de costas. Mas acordado, bruços é ótimo para desenvolvimento!', 'desenvolvimento', 'pt', 0, 'true');